private static boolean isExpiredAccessToken() {
		if (lastGetAccessTokenTime == null) {
			return true;
		}
		// 1.5小时以后的就算失效
		long existTime = 5400000L;
		long now = System.currentTimeMillis();
		if (now - lastGetAccessTokenTime.getTime() > existTime) {
			return true;
		}
		return false;
	}

